import{_ as i,o as a,c as o,a5 as r}from"./chunks/framework.B5tqjWbr.js";const c=JSON.parse('{"title":"UPS电源软件开发 — 课程体系大纲","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"UPS电源软件开发 — 课程体系大纲","tags":["power-electronics"],"status":"learning","summary":"- 由简到繁：先后备式再在线式 - 硬软结合：每个拓扑先理解硬件原理再写控制代码 - 任务驱动：每课一个可验证的技能点 - 面试导向：关键知识点对标面试高频问题"},"headers":[],"relativePath":"content/power/NOTES.md","filePath":"content/power/NOTES.md","lastUpdated":null}'),t={name:"content/power/NOTES.md"};function e(s,l,n,h,u,d){return a(),o("div",null,[...l[0]||(l[0]=[r('<h1 id="ups电源软件开发-—-课程体系大纲" tabindex="-1">UPS电源软件开发 — 课程体系大纲 <a class="header-anchor" href="#ups电源软件开发-—-课程体系大纲" aria-label="Permalink to &quot;UPS电源软件开发 — 课程体系大纲&quot;">​</a></h1><h2 id="课程设计原则" tabindex="-1">课程设计原则 <a class="header-anchor" href="#课程设计原则" aria-label="Permalink to &quot;课程设计原则&quot;">​</a></h2><ul><li>由简到繁：先后备式再在线式</li><li>硬软结合：每个拓扑先理解硬件原理再写控制代码</li><li>任务驱动：每课一个可验证的技能点</li><li>面试导向：关键知识点对标面试高频问题</li></ul><hr><h2 id="phase-1-基础筑基-第1-6课" tabindex="-1">Phase 1: 基础筑基（第1-6课） <a class="header-anchor" href="#phase-1-基础筑基-第1-6课" aria-label="Permalink to &quot;Phase 1: 基础筑基（第1-6课）&quot;">​</a></h2><h3 id="第1课-ups电源系统全景认知" tabindex="-1">第1课：UPS电源系统全景认知 <a class="header-anchor" href="#第1课-ups电源系统全景认知" aria-label="Permalink to &quot;第1课：UPS电源系统全景认知&quot;">​</a></h3><ul><li>UPS的定义、分类（后备式/在线式/在线互动式）</li><li>在线式UPS双变换架构框图</li><li>各功率级功能定位：PFC→DC-DC→逆变器</li><li>UPS软件开发者的知识地图</li><li><strong>技能点</strong>：能画出在线式UPS系统框图并解释每个模块</li></ul><h3 id="第2课-电力电子基础——开关器件与基本拓扑" tabindex="-1">第2课：电力电子基础——开关器件与基本拓扑 <a class="header-anchor" href="#第2课-电力电子基础——开关器件与基本拓扑" aria-label="Permalink to &quot;第2课：电力电子基础——开关器件与基本拓扑&quot;">​</a></h3><ul><li>MOSFET/IGBT/SiC器件特性与选型</li><li>Buck/Boost/Buck-Boost基本拓扑</li><li>开关损耗与导通损耗</li><li>死区时间的概念与计算</li><li><strong>技能点</strong>：能根据规格选择合适的开关器件和拓扑</li></ul><h3 id="第3课-pwm调制技术——从spwm到svpwm" tabindex="-1">第3课：PWM调制技术——从SPWM到SVPWM <a class="header-anchor" href="#第3课-pwm调制技术——从spwm到svpwm" aria-label="Permalink to &quot;第3课：PWM调制技术——从SPWM到SVPWM&quot;">​</a></h3><ul><li>SPWM原理与实现（正弦表+三角波比较）</li><li>单极性/双极性SPWM</li><li>SVPWM原理（两电平空间矢量）</li><li>扇区判断与矢量作用时间计算</li><li><strong>技能点</strong>：能在MCU上实现SPWM发波</li></ul><h3 id="第4课-数字控制基础——从连续到离散" tabindex="-1">第4课：数字控制基础——从连续到离散 <a class="header-anchor" href="#第4课-数字控制基础——从连续到离散" aria-label="Permalink to &quot;第4课：数字控制基础——从连续到离散&quot;">​</a></h3><ul><li>s域到z域的变换（双线性变换/零阶保持）</li><li>PI控制器的离散化实现</li><li>电压环/电流环设计方法</li><li>采样与PWM同步机制</li><li><strong>技能点</strong>：能设计并实现数字PI控制器</li></ul><h3 id="第5课-锁相环与坐标变换" tabindex="-1">第5课：锁相环与坐标变换 <a class="header-anchor" href="#第5课-锁相环与坐标变换" aria-label="Permalink to &quot;第5课：锁相环与坐标变换&quot;">​</a></h3><ul><li>Clark变换（abc→αβ）</li><li>Park变换（αβ→dq）</li><li>SRF-PLL（同步旋转坐标系锁相环）</li><li>电网同步与频率跟踪</li><li><strong>技能点</strong>：能实现SRF-PLL并理解dq解耦</li></ul><h3 id="第6课-adc采样与信号调理" tabindex="-1">第6课：ADC采样与信号调理 <a class="header-anchor" href="#第6课-adc采样与信号调理" aria-label="Permalink to &quot;第6课：ADC采样与信号调理&quot;">​</a></h3><ul><li>电压/电流采样电路原理</li><li>运放调理与偏置电路</li><li>ADC同步采样与多路复用</li><li>采样校准与偏移消除</li><li><strong>技能点</strong>：能设计采样方案并编写校准代码</li></ul><hr><h2 id="phase-2-核心拓扑与控制-第7-14课" tabindex="-1">Phase 2: 核心拓扑与控制（第7-14课） <a class="header-anchor" href="#phase-2-核心拓扑与控制-第7-14课" aria-label="Permalink to &quot;Phase 2: 核心拓扑与控制（第7-14课）&quot;">​</a></h2><h3 id="第7课-单相pfc控制" tabindex="-1">第7课：单相PFC控制 <a class="header-anchor" href="#第7课-单相pfc控制" aria-label="Permalink to &quot;第7课：单相PFC控制&quot;">​</a></h3><ul><li>Boost PFC拓扑与工作原理</li><li>平均电流控制模式</li><li>电压外环+电流内环设计</li><li>输入电压前馈</li><li><strong>技能点</strong>：能编写单相PFC控制代码</li></ul><h3 id="第8课-三相pfc与维也纳整流器" tabindex="-1">第8课：三相PFC与维也纳整流器 <a class="header-anchor" href="#第8课-三相pfc与维也纳整流器" aria-label="Permalink to &quot;第8课：三相PFC与维也纳整流器&quot;">​</a></h3><ul><li>三相Boost PFC拓扑</li><li>维也纳整流器拓扑结构（三电平三开关）</li><li>三电平SVPWM原理</li><li>中点电位平衡控制</li><li><strong>技能点</strong>：能理解维也纳整流器控制架构</li></ul><h3 id="第9课-三电平svpwm深入" tabindex="-1">第9课：三电平SVPWM深入 <a class="header-anchor" href="#第9课-三电平svpwm深入" aria-label="Permalink to &quot;第9课：三电平SVPWM深入&quot;">​</a></h3><ul><li>三电平空间矢量图（大六边形/小六边形）</li><li>扇区判断与矢量选择</li><li>冗余矢量与中点平衡</li><li>开关序列优化</li><li><strong>技能点</strong>：能实现三电平SVPWM发波算法</li></ul><h3 id="第10课-单相逆变器控制" tabindex="-1">第10课：单相逆变器控制 <a class="header-anchor" href="#第10课-单相逆变器控制" aria-label="Permalink to &quot;第10课：单相逆变器控制&quot;">​</a></h3><ul><li>全桥逆变拓扑</li><li>SPWM发波与LC滤波器设计</li><li>电压有效值外环+瞬时值内环</li><li>PR控制器在逆变器中的应用</li><li><strong>技能点</strong>：能编写单相逆变器控制代码</li></ul><h3 id="第11课-三相逆变器控制" tabindex="-1">第11课：三相逆变器控制 <a class="header-anchor" href="#第11课-三相逆变器控制" aria-label="Permalink to &quot;第11课：三相逆变器控制&quot;">​</a></h3><ul><li>三相全桥逆变拓扑</li><li>SVPWM发波</li><li>dq坐标系下的电压/电流双闭环</li><li>并网逆变器与离网逆变器区别</li><li><strong>技能点</strong>：能设计三相逆变器控制环路</li></ul><h3 id="第12课-llc谐振变换器原理与控制" tabindex="-1">第12课：LLC谐振变换器原理与控制 <a class="header-anchor" href="#第12课-llc谐振变换器原理与控制" aria-label="Permalink to &quot;第12课：LLC谐振变换器原理与控制&quot;">​</a></h3><ul><li>LLC拓扑结构（半桥/全桥）</li><li>谐振腔工作原理（Lr, Lm, Cr）</li><li>直流增益特性曲线</li><li>PFM控制策略</li><li>ZVS实现条件</li><li><strong>技能点</strong>：能理解LLC工作原理并设计控制方案</li></ul><h3 id="第13课-双向dc-dc与电池管理" tabindex="-1">第13课：双向DC-DC与电池管理 <a class="header-anchor" href="#第13课-双向dc-dc与电池管理" aria-label="Permalink to &quot;第13课：双向DC-DC与电池管理&quot;">​</a></h3><ul><li>双向Buck-Boost拓扑</li><li>充电/放电模式切换</li><li>电池管理（CC-CV充电、SOC估算）</li><li>均流控制</li><li><strong>技能点</strong>：能设计电池充放电控制逻辑</li></ul><h3 id="第14课-多级联调——pfc-dc-dc-逆变器协同" tabindex="-1">第14课：多级联调——PFC+DC-DC+逆变器协同 <a class="header-anchor" href="#第14课-多级联调——pfc-dc-dc-逆变器协同" aria-label="Permalink to &quot;第14课：多级联调——PFC+DC-DC+逆变器协同&quot;">​</a></h3><ul><li>级联系统稳定性分析</li><li>母线电压波动与抑制</li><li>启动时序设计</li><li>各级保护协调</li><li><strong>技能点</strong>：能设计多级联调方案</li></ul><hr><h2 id="phase-3-系统集成-第15-19课" tabindex="-1">Phase 3: 系统集成（第15-19课） <a class="header-anchor" href="#phase-3-系统集成-第15-19课" aria-label="Permalink to &quot;Phase 3: 系统集成（第15-19课）&quot;">​</a></h2><h3 id="第15课-后备式ups完整软件设计" tabindex="-1">第15课：后备式UPS完整软件设计 <a class="header-anchor" href="#第15课-后备式ups完整软件设计" aria-label="Permalink to &quot;第15课：后备式UPS完整软件设计&quot;">​</a></h3><ul><li>系统状态机设计（市电正常/电池供电/故障）</li><li>市电检测与切换逻辑</li><li>逆变器启停控制</li><li>报警与保护机制</li><li><strong>技能点</strong>：能完成后备式UPS固件框架</li></ul><h3 id="第16课-在线式ups完整软件设计" tabindex="-1">第16课：在线式UPS完整软件设计 <a class="header-anchor" href="#第16课-在线式ups完整软件设计" aria-label="Permalink to &quot;第16课：在线式UPS完整软件设计&quot;">​</a></h3><ul><li>双变换架构的软件实现</li><li>旁路切换逻辑（静态旁路/维修旁路）</li><li>电池模式/市电模式/旁路模式切换</li><li>零切换实现原理</li><li><strong>技能点</strong>：能设计在线式UPS状态机</li></ul><h3 id="第17课-并机与冗余设计" tabindex="-1">第17课：并机与冗余设计 <a class="header-anchor" href="#第17课-并机与冗余设计" aria-label="Permalink to &quot;第17课：并机与冗余设计&quot;">​</a></h3><ul><li>主从均流控制</li><li>无主均流控制</li><li>并机通信协议</li><li>N+1冗余设计</li><li><strong>技能点</strong>：能理解并机控制原理</li></ul><h3 id="第18课-保护机制设计" tabindex="-1">第18课：保护机制设计 <a class="header-anchor" href="#第18课-保护机制设计" aria-label="Permalink to &quot;第18课：保护机制设计&quot;">​</a></h3><ul><li>过流/短路保护（硬件+软件）</li><li>过压/欠压保护</li><li>过温保护</li><li>电池欠压保护</li><li>故障记录与诊断</li><li><strong>技能点</strong>：能设计完整的保护体系</li></ul><h3 id="第19课-通信协议与远程监控" tabindex="-1">第19课：通信协议与远程监控 <a class="header-anchor" href="#第19课-通信协议与远程监控" aria-label="Permalink to &quot;第19课：通信协议与远程监控&quot;">​</a></h3><ul><li>Modbus协议实现</li><li>CAN通信（并机/扩展）</li><li>SNMP网络监控</li><li>上下位机通信协议设计</li><li><strong>技能点</strong>：能实现Modbus通信</li></ul><hr><h2 id="phase-4-架构设计与对比-第20-24课" tabindex="-1">Phase 4: 架构设计与对比（第20-24课） <a class="header-anchor" href="#phase-4-架构设计与对比-第20-24课" aria-label="Permalink to &quot;Phase 4: 架构设计与对比（第20-24课）&quot;">​</a></h2><h3 id="第20课-ups固件分层架构设计" tabindex="-1">第20课：UPS固件分层架构设计 <a class="header-anchor" href="#第20课-ups固件分层架构设计" aria-label="Permalink to &quot;第20课：UPS固件分层架构设计&quot;">​</a></h3><ul><li>HAL层/驱动层/中间件层/应用层</li><li>硬件抽象与平台移植</li><li>配置管理（参数表/特征字）</li><li>模块间接口设计</li><li><strong>技能点</strong>：能设计UPS固件分层架构</li></ul><h3 id="第21课-rtos任务划分与实时性保障" tabindex="-1">第21课：RTOS任务划分与实时性保障 <a class="header-anchor" href="#第21课-rtos任务划分与实时性保障" aria-label="Permalink to &quot;第21课：RTOS任务划分与实时性保障&quot;">​</a></h3><ul><li>任务识别与优先级分配</li><li>中断与任务分工</li><li>资源共享与同步机制</li><li>WCET分析与deadline保障</li><li><strong>技能点</strong>：能设计RTOS任务架构</li></ul><h3 id="第22课-ota升级与配置管理" tabindex="-1">第22课：OTA升级与配置管理 <a class="header-anchor" href="#第22课-ota升级与配置管理" aria-label="Permalink to &quot;第22课：OTA升级与配置管理&quot;">​</a></h3><ul><li>Bootloader设计</li><li>双区备份与回滚</li><li>固件签名验证</li><li>参数配置与出厂设置</li><li><strong>技能点</strong>：能设计OTA升级方案</li></ul><h3 id="第23课-面试实战——ups软件开发高频考点" tabindex="-1">第23课：面试实战——UPS软件开发高频考点 <a class="header-anchor" href="#第23课-面试实战——ups软件开发高频考点" aria-label="Permalink to &quot;第23课：面试实战——UPS软件开发高频考点&quot;">​</a></h3><ul><li>拓扑原理面试题</li><li>控制算法面试题</li><li>系统设计面试题</li><li>项目经验表述技巧</li><li><strong>技能点</strong>：能自信应对UPS开发面试</li></ul><h3 id="第24课-电源控制-vs-电机控制——跨界对比与知识迁移" tabindex="-1">第24课：电源控制 vs 电机控制——跨界对比与知识迁移 <a class="header-anchor" href="#第24课-电源控制-vs-电机控制——跨界对比与知识迁移" aria-label="Permalink to &quot;第24课：电源控制 vs 电机控制——跨界对比与知识迁移&quot;">​</a></h3><ul><li><strong>拓扑对比</strong>：逆变器（电源）vs 逆变器（电机）——同一硬件，不同目标</li><li><strong>控制目标对比</strong>：电压源（恒压）vs 电流源（恒转矩/恒速）</li><li><strong>坐标系对比</strong>：电网同步dq（锁相环）vs 转子同步dq（编码器/观测器）</li><li><strong>PLL对比</strong>：电网PLL（跟踪电网频率）vs 转子位置观测器（无感FOC）</li><li><strong>电流环对比</strong>：PFC电流环（正弦跟踪）vs FOC电流环（转矩/磁通解耦）</li><li><strong>电压环对比</strong>：PFC电压环（10Hz低带宽）vs 电机速度环（100Hz+高带宽）</li><li><strong>PWM对比</strong>：电源SPWM/SVPWM（固定频率）vs 电机SVPWM（变频变压）</li><li><strong>采样对比</strong>：电源（PEAK点同步采样）vs 电机（下管导通中点采样）</li><li><strong>保护对比</strong>：过流/过压（电源）vs 过流/堵转/飞车（电机）</li><li><strong>代码架构对比</strong>：电源固件（状态机驱动）vs 电机固件（FOC循环驱动）</li><li><strong>职业路径</strong>：电源工程师 vs 电机工程师的技能差异与互通性</li><li><strong>技能点</strong>：能清晰阐述电源控制与电机控制的异同，具备跨领域知识迁移能力</li></ul><blockquote><p><strong>设计说明</strong>：本课作为独立课程系统对比电源与电机控制，同时每课末尾增加简短的&quot;电机控制对照&quot;小节，帮助有电机背景的学习者快速建立关联。这种&quot;点面结合&quot;的方式既保证系统性，又兼顾每课的即时关联。</p></blockquote><hr><h2 id="补充课" tabindex="-1">补充课 <a class="header-anchor" href="#补充课" aria-label="Permalink to &quot;补充课&quot;">​</a></h2><h3 id="补充课-buck-boost工作模式深度分析——ccm-dcm-bcm的工程意义" tabindex="-1">补充课：Buck/Boost工作模式深度分析——CCM/DCM/BCM的工程意义 <a class="header-anchor" href="#补充课-buck-boost工作模式深度分析——ccm-dcm-bcm的工程意义" aria-label="Permalink to &quot;补充课：Buck/Boost工作模式深度分析——CCM/DCM/BCM的工程意义&quot;">​</a></h3><ul><li>CCM/DCM/BCM三种工作模式的定义与物理本质</li><li>Buck/Boost变换器在三种模式下的工作模态分析</li><li>边界条件推导与电感值计算（保证CCM的最小电感）</li><li>DCM对控制的影响——传递函数变化（二阶→一阶）</li><li>Boost PFC：CRM vs CCM控制策略对比</li><li>轻载DCM的4种处理策略（Burst Mode/增益调度/强制CCM/降频）</li><li>UPS实际案例：双向DC-DC轻载振荡、PFC轻载母线过压</li><li><strong>技能点</strong>：能计算电感值、判断CCM/DCM状态、选择轻载处理策略</li></ul><h3 id="补充课2-控制设计深度——从理论到调试的完整方法论" tabindex="-1">补充课2：控制设计深度——从理论到调试的完整方法论 <a class="header-anchor" href="#补充课2-控制设计深度——从理论到调试的完整方法论" aria-label="Permalink to &quot;补充课2：控制设计深度——从理论到调试的完整方法论&quot;">​</a></h3><ul><li>控制设计5步法（建模→开环→控制器→稳定性→整定）</li><li>被控对象建模（Buck/Boost小信号模型、RHP零点、LC滤波器）</li><li>PI参数整定——带宽法（电流环+电压环完整数值实例）</li><li>PR控制器设计（传递函数推导、准PR、Tustin离散化、谐波补偿）</li><li>环路稳定性分析（Bode图判稳、常见不稳定原因、示波器判断法）</li><li>控制调试实战（先内环后外环、PI调试口诀、5个常见问题）</li><li>前馈设计（占空比前馈、V²rms前馈、反电动势前馈）</li><li><strong>技能点</strong>：能独立完成PI/PR参数整定，能调试不稳定控制环路</li></ul><h3 id="补充课3-ups行业与产品知识——面试必懂的领域背景" tabindex="-1">补充课3：UPS行业与产品知识——面试必懂的领域背景 <a class="header-anchor" href="#补充课3-ups行业与产品知识——面试必懂的领域背景" aria-label="Permalink to &quot;补充课3：UPS行业与产品知识——面试必懂的领域背景&quot;">​</a></h3><ul><li>UPS行业标准体系（IEC 62040/61000-3-2、GB/T 7260、UL 1778）</li><li>UPS关键规格解读（输入/输出/电池/效率，哪些由软件决定）</li><li>UPS架构选型——按功率等级（&lt;1kVA到100kVA+的MCU/拓扑/方案）</li><li>UPS市场格局（国际一线+中国厂商+行业趋势）</li><li>UPS软件开发的日常工作（项目流程/工具/核心能力）</li><li>UPS vs 其他电源产品对比（逆变器/充电桩/光伏/PCS/服务器电源）</li><li>面试高频UPS领域问题（10题详细答案）</li><li><strong>技能点</strong>：能自信应对UPS领域知识面试题，理解行业背景</li></ul><h3 id="补充课4-先修知识——数学-电路-电力电子-自动控制基础" tabindex="-1">补充课4：先修知识——数学/电路/电力电子/自动控制基础 <a class="header-anchor" href="#补充课4-先修知识——数学-电路-电力电子-自动控制基础" aria-label="Permalink to &quot;补充课4：先修知识——数学/电路/电力电子/自动控制基础&quot;">​</a></h3><ul><li>数学：复数与相量、拉普拉斯变换、Z变换、矩阵运算、三角函数</li><li>电路：KVL/KCL、RLC电路、一阶/二阶响应、功率计算、三相电路</li><li>电力电子：开关器件、PWM原理、硬开关/软开关、CCM/DCM、隔离拓扑</li><li>自动控制：传递函数、一阶/二阶系统、稳定性判据、PID、带宽、前馈</li><li>数字控制：采样量化、延迟影响、离散化方法</li><li>每个知识点标注&quot;在UPS中的哪里用到&quot;</li><li><strong>技能点</strong>：补齐完成整个课程体系所需的先修知识</li></ul><h3 id="补充课5-易混淆概念辨析——ups-电源开发中的-双胞胎-概念" tabindex="-1">补充课5：易混淆概念辨析——UPS/电源开发中的&quot;双胞胎&quot;概念 <a class="header-anchor" href="#补充课5-易混淆概念辨析——ups-电源开发中的-双胞胎-概念" aria-label="Permalink to &quot;补充课5：易混淆概念辨析——UPS/电源开发中的&quot;双胞胎&quot;概念&quot;">​</a></h3><ul><li>20组易混淆概念：功率因数角vs功角、SPWM vs SVPWM、PI vs PR、CCM vs DCM、在线式vs后备式、旁路vs维修旁路、前馈vs反馈、离网vs并网、均流vs同步、PF vs THD等</li><li>每组：定义对比→本质区别→面试答题要点→记忆口诀</li><li>综合自测4道场景判断题</li><li><strong>技能点</strong>：准确区分面试中容易混淆的概念，避免&quot;张冠李戴&quot;</li></ul>',72)])])}const q=i(t,[["render",e]]);export{c as __pageData,q as default};
